const fs = require("fs");
const path = require("path");

const PATCH_NAME = "BARNDAKSA_CUSTOMER_FAST_APP_PATCH";
const PATCH_PAYLOAD = [{"path":"app/api/customer-fast/[slug]/route.ts","encoding":"base64","content":""},{"path":"app/api/pwa/[slug]/manifest/route.ts","encoding":"base64","content":""},{"path":"app/api/pwa/[slug]/sw/route.ts","encoding":"base64","content":""},{"path":"app/app/[slug]/page.tsx","encoding":"base64","content":""},{"path":"components/cafe/brand-pwa-install-section.tsx","encoding":"base64","content":""},{"path":"components/customer-app/customer-fast-app-client.tsx","encoding":"base64","content":""}];
const PATCH_MANIFEST = {"name":"BARNDAKSA_CUSTOMER_FAST_APP_PATCH","createdAt":"2026-06-17","description":"Adds the lightweight customer PWA layer at /app/[slug] and points brand install flow to the fast app.","databaseChanges":false,"files":["app/api/customer-fast/[slug]/route.ts","app/api/pwa/[slug]/manifest/route.ts","app/api/pwa/[slug]/sw/route.ts","app/app/[slug]/page.tsx","components/cafe/brand-pwa-install-section.tsx","components/customer-app/customer-fast-app-client.tsx"],"runFromProjectRoot":"node BARNDAKSA_CUSTOMER_FAST_APP_PATCH/apply-patch.cjs","runFromPatchFolder":"cd BARNDAKSA_CUSTOMER_FAST_APP_PATCH && node apply-patch.cjs"};

function fail(message) {
  console.error(`\n[${PATCH_NAME}] ${message}\n`);
  process.exit(1);
}

function findProjectRoot() {
  const candidates = [
    process.cwd(),
    path.dirname(__dirname),
    path.resolve(__dirname, ".."),
  ];

  for (const candidate of candidates) {
    if (candidate && fs.existsSync(path.join(candidate, "package.json"))) {
      return candidate;
    }
  }

  fail("ضع مجلد الباتش داخل جذر المشروع ثم شغل السكربت من جذر المشروع أو من داخل مجلد الباتش. لم أجد package.json.");
}

function removeDirIfExists(target) {
  try {
    if (fs.existsSync(target) && fs.statSync(target).isDirectory()) {
      fs.rmSync(target, { recursive: true, force: true });
      console.log(`✓ Removed stale folder: ${path.relative(process.cwd(), target) || target}`);
    }
  } catch (error) {
    console.warn(`! Could not remove stale folder ${target}: ${error.message}`);
  }
}

function writeFileSafe(projectRoot, relativePath, contentBuffer, backupRoot) {
  const target = path.join(projectRoot, relativePath);
  const backup = path.join(backupRoot, relativePath);
  fs.mkdirSync(path.dirname(target), { recursive: true });

  if (fs.existsSync(target)) {
    fs.mkdirSync(path.dirname(backup), { recursive: true });
    fs.copyFileSync(target, backup);
  }

  fs.writeFileSync(target, contentBuffer);
  console.log(`✓ ${relativePath}`);
}

const projectRoot = findProjectRoot();
const stamp = new Date().toISOString().replace(/[:.]/g, "-");
const backupRoot = path.join(projectRoot, ".barndaksa-patch-backups", `${PATCH_NAME}-${stamp}`);

console.log(`\nApplying ${PATCH_NAME}...`);
console.log(`Project root: ${projectRoot}`);
console.log(`Backup root: ${backupRoot}\n`);

for (const file of PATCH_PAYLOAD) {
  if (!file.path || file.encoding !== "base64" || typeof file.content !== "string") {
    fail(`Invalid embedded patch payload for ${file.path || "unknown file"}`);
  }

  const cleanPath = file.path.replaceAll("\\\\", "/");
  if (cleanPath.includes("..") || path.isAbsolute(cleanPath)) {
    fail(`Unsafe patch path blocked: ${file.path}`);
  }

  writeFileSafe(projectRoot, cleanPath, Buffer.from(file.content, "base64"), backupRoot);
}

console.log("\nCleaning old extracted patch payload folders so TypeScript does not scan them...");
removeDirIfExists(path.join(__dirname, "patch-files"));
removeDirIfExists(path.join(__dirname, "files"));
removeDirIfExists(path.join(projectRoot, "patch-files"));

console.log("\nDone. Next commands:");
console.log("npm exec tsc -- --noEmit");
console.log("npm run build");
console.log("\nNew customer app route example:");
console.log("/app/test-cafe");

if (PATCH_MANIFEST.databaseChanges === false) {
  console.log("\nDatabase: no SQL migration required for this patch.");
}
